export default "// SR Latch\r\n// s=1, r=0 = set Q to 1\r\n// s=0, r=1 = reset Q to 0\r\n// s=0, r=0 = hold/store current value of Q\r\n// s=1, r=1 = not allowed\r\n\r\nmodule SRLatch (\r\n  input r, s,\r\n  output Q );\r\n\r\n  wire Qn;\r\n  assign Q = r ~| Qn;\r\n  assign Qn = Q ~| s;\r\n  \r\nendmodule\r\n\r\nmodule Main(\r\n  input r, s,\r\n  output Q\r\n); \r\n\r\n  SRLatch latch(\r\n\t\t.r(r),\r\n\t\t.s(s),\r\n\t\t.Q(Q)\r\n  );\r\n\r\n  test begin\r\n    #0  {s=0, r=1};\r\n    #1  {s=1, r=0};\r\n    #2  {s=0, r=0};\r\n    #5  {s=0, r=1};\r\n    #8  {s=1, r=0};\r\n    #10 {s=0, r=0};\r\n    #12;\r\n  end\r\nendmodule";