export default "// 4 bit adder behavioural model (experimental)\r\n\r\nmodule FullAdder (\r\n  input a, b, ci,\r\n  output sum, cout );\r\n\r\n  wire [1:0] res;\r\n  buffer(res);\r\n\r\n  always @(*)\r\n    begin\r\n      res = a + b + ci;\r\n    end\r\n\r\n  assign sum = res[0];\r\n  assign cout = res[1];\r\nendmodule\r\n\r\nmodule Add4 (\r\n  input [3:0] a, b,\r\n  input ci,\r\n  output [3:0] sum,\r\n  output cout );\r\n\r\n  wire [2:0] cob;\r\n  buffer(cob);\r\n  buffer(sum);\r\n  buffer(cout);\r\n\r\n  FullAdder fa0(.a(a[0]), .b(b[0]), .ci(ci),     .sum(sum[0]), .cout(cob[0]));\r\n  FullAdder fa1(.a(a[1]), .b(b[1]), .ci(cob[0]), .sum(sum[1]), .cout(cob[1]));\r\n  FullAdder fa2(.a(a[2]), .b(b[2]), .ci(cob[1]), .sum(sum[2]), .cout(cob[2]));\r\n  FullAdder fa3(.a(a[3]), .b(b[3]), .ci(cob[2]), .sum(sum[3]), .cout(cout));\r\nendmodule\r\n\r\n\r\nmodule Main(\r\n  input [3:0] x, y,\r\n  input ci,\r\n  output [3:0] SUM, COUT\r\n); \r\n\r\n  Add4 myAdder(\r\n\t\t.a(x),\r\n\t\t.b(y),\r\n    .ci(ci),\r\n\t\t.sum(SUM),\r\n\t\t.cout(COUT)\r\n  );\r\n\r\n  test begin\r\n    #0  { ci=0, x=0, y=0 };\r\n    #1  { ci=0, x=0, y=1 };\r\n    #2  { ci=0, x=1, y=1 };\r\n    #3  { ci=0, x=1, y=2 };\r\n    #4  { ci=0, x=1, y=2 };\r\n    #5  { ci=0, x=1, y=2 };\r\n    #6  { ci=0, x=2, y=2 };\r\n    #8;\r\n  end\r\nendmodule";