export default " \r\n/*\r\nSum of products from truth table. \r\nFind minterm (contains all inputs and is true) for each true result\r\nSum the minterm products\r\n\r\nA B | F | minterm\r\n0 0 | 0 | -\r\n0 1 | 1 | A` * B\r\n1 0 | 1 | A * B`\r\n1 1 | 0 | -\r\n\r\nF = (A` * B) + (A * B`)\r\n\r\n*/\r\n\r\nmodule Main(\r\n  input A, B,\r\n  output F\r\n); \r\n\r\n  wire Fe;\r\n  assign Fe = (~A & B) | (A & ~B);\r\n\r\n  response(F, Fe); // buffer Fe gate to output F\r\n\r\n  test begin\r\n    #0  {A=0, B=0};\r\n    #2  {A=0, B=1};\r\n    #4  {A=1, B=0};\r\n    #6  {A=1, B=1};\r\n    #8;\r\n  end\r\nendmodule";