export default "// S`R` Latch\r\n// complement of SR Latch using nand gates\r\n// function of s and r are reversed\r\n// s=1, r=0 = reset Q to 0\r\n// s=0, r=1 = set Q to 1\r\n// s=1, r=1 = hold/store current value of Q\r\n// s=0, r=0 = not allowed\r\n\r\nmodule SRLatchComplement (\r\n  input r, s,\r\n  output Q );\r\n\r\n  wire Qn;\r\n  assign Q = s ~& Qn;\r\n  assign Qn = Q ~& r;\r\nendmodule\r\n\r\nmodule Main(\r\n  input r, s,\r\n  output Q\r\n); \r\n\r\n  SRLatchComplement latch(\r\n    .r(r),\r\n\t\t.s(s),\r\n\t\t.Q(Q)\r\n  );\r\n\r\n  test begin\r\n    #0  {r=1, s=1};\r\n    #2  {s=1, r=0};\r\n    // #4  {s=1, r=1}; do not do this\r\n    #4  {s=1, r=1};\r\n    #8  {s=0, r=1};\r\n    #10 {s=1, r=1};\r\n    #12;\r\n  end\r\nendmodule";