export default "/* Full adder\r\nSimplified instead of two half adders\r\n*/\r\n\r\n\r\nmodule FullAdder (\r\n  input a, b, cin,\r\n  output S, Cout);\r\n\r\n  wire p, g;\r\n\r\n  assign p = a ^ b;\r\n  assign g = a & b;\r\n\r\n  assign S = p ^ cin;\r\n  assign Cout = g | (p & cin); // remove brackets to test operator precedence\r\nendmodule\r\n\r\nmodule Main (\r\n  input a, b, cin,\r\n  output Sum, Cout\r\n);\r\n\r\n  FullAdder full(\r\n\t\t.a(a),\r\n\t\t.b(b),\r\n    .cin(cin),\r\n\t\t.S(S),\r\n\t\t.Cout(Cout)\r\n  );\r\n\r\n \r\n\ttest begin\r\n\t\t#0  {cin=0, a=0, b=0};\r\n    #1  {cin=0, a=0, b=1};\r\n    #2  {cin=0, a=1, b=0};\r\n    #3  {cin=0, a=1, b=1};\r\n\t\t#4  {cin=1, a=0, b=0};\r\n    #5  {cin=1, a=0, b=1};\r\n    #6  {cin=1, a=1, b=0};\r\n    #7  {cin=1, a=1, b=1};\r\n    #8;\r\n\tend\r\nendmodule";