export default "// One bit half adder\r\n\r\nmodule HalfAdder (\r\n  input a, b,\r\n  output S, Cout);\r\n\r\n  assign S = a ^ b;\r\n  assign Cout = a & b;\r\nendmodule\r\n\r\nmodule Main (\r\n  input a, b,\r\n  output Sum, Cout\r\n);\r\n\r\n  HalfAdder half(\r\n\t\t.a(a),\r\n\t\t.b(b),\r\n\t\t.S(Sum),\r\n\t\t.Cout(Cout)\r\n  );\r\n\r\n\ttest begin\r\n\t\t#0  {a=0, b=0};\r\n    #2  {a=0, b=1};\r\n    #4  {a=1, b=0};\r\n    #6  {a=1, b=1};\r\n    #8;\r\n\tend\r\nendmodule";