export default "// D Flip Flop\r\n\r\nmodule DFF (\r\n\tinput clk, dIn,\r\n\toutput q3);\r\n\r\n\twire not_d_in, d_nand_a, d_nand_c, q_;\r\n\r\n\tnot( not_d_in, dIn );\r\n\tnand( d_nand_a, dIn, clk );\r\n\tnand( q3, d_nand_a, q_ );\r\n\tnand( d_nand_c, not_d_in, clk );\r\n  nand( q_, d_nand_c, q3);\r\nendmodule\r\n\r\nmodule DFFE (\r\n  input clk, dIn, dEnable,\r\n  output q2);\r\n\r\n  wire gatedClk;\r\n\r\n  buffer(q2);\r\n  and(gatedClk, clk, dEnable);\r\n  \r\n  DFF dff(.clk(gatedClk), .dIn(dIn), .q3(q2));\r\n\r\n\r\nendmodule\r\n\r\nmodule Main(\r\n  input A, E, clock,\r\n  output q1);\r\n\r\n  DFFE dffe(.clk(clock), .dIn(A), .dEnable(E), .q2(q1));\r\n\r\n  test begin\r\n    #0  { E=1 };\r\n    #1  { A=1, E=0 };\r\n    #7  { E=1 };\r\n    #9  { A=0, E=0 };\r\n    #12;\r\n  end\r\nendmodule";