export default "// SR Latch with Enable with data line instead of separate set and reset lines\r\n// the clock signals the latch to follow the data line\r\n// when clock is 0 the latch holds the last Q\r\n\r\nmodule DLatch (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  initial Q = 0;\r\n  initial Qn = 1;\r\n\r\n  wire u3, u4;\r\n  assign u3 = d ~& c;\r\n  assign u4 = ~d ~& c;\r\n\r\n  assign Q = u3 ~& Qn;\r\n  assign Qn = u4 ~& Q;\r\nendmodule\r\n\r\nmodule Main(\r\n  input d, c,\r\n  output Q, Qn\r\n); \r\n\r\n  DLatch latch(\r\n    .d(d),\r\n\t\t.c(c),\r\n\t\t.Q(Q)\r\n  );\r\n\r\n  test begin\r\n    #0  {c=0, d=0};\r\n    #1  {c=0, d=1};\r\n    #2  {c=0, d=0};\r\n    #3  {c=0, d=1};\r\n    #4  {c=1, d=0};\r\n    #5  {c=1, d=1};\r\n    #6  {c=1, d=0};\r\n    #7  {c=1, d=1};\r\n    #8  {c=0, d=0};\r\n    #9  {c=0, d=1};\r\n    #10  {c=0, d=0};\r\n    #11  {c=0, d=1};\r\n    #12;\r\n  end\r\nendmodule";