export default "// Master-slave d-flipflop\r\n\r\nmodule DFlipFlop (\r\n  input clk, reset, d,\r\n  output Q);\r\n\r\n  reg Q;\r\n\r\n  initial Q=1;\r\n\r\n  always @(posedge clk)\r\n    begin\r\n      if (reset) Q=0;\r\n      else Q=d;\r\n    end\r\nendmodule\r\n\r\n\r\nmodule Main(\r\n  input c, reset, d,\r\n  output Qm\r\n); \r\n\r\n  DFlipFlop dff(\r\n\t\t.clk(c),\r\n\t\t.reset(reset),\r\n    .d(d),\r\n\t\t.Q(Qm)\r\n  );\r\n\r\n  test begin\r\n    #0  { d=0, c=0, reset=0 };\r\n    #1  { d=0, c=0, reset=0 };\r\n    #2  { d=0, c=1, reset=0 };\r\n    #3  { d=1, c=1, reset=0 };\r\n    #4  { d=0, c=1, reset=0 };\r\n    #5  { d=0, c=0, reset=0 };\r\n    #6  { d=1, c=1, reset=0 };\r\n    #7  { d=0, c=1, reset=0 };\r\n    #8  { d=1, c=1, reset=0 };\r\n    #9  { d=1, c=0, reset=0 };\r\n    #10 { d=1, c=1, reset=1 };\r\n    #12;\r\n  end\r\nendmodule";