export default "// Master-slave d-flipflop\r\n\r\nmodule DLatch (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  initial Q = 0;\r\n  initial Qn = 1;\r\n\r\n  wire u3, u4;\r\n  assign u3 = d ~& c;\r\n  assign u4 = ~d ~& c;\r\n\r\n  assign Q = u3 ~& Qn;\r\n  assign Qn = u4 ~& Q;\r\nendmodule\r\n\r\nmodule DFlipFlop (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire cn, cnn;\r\n  not(cn, c);\r\n  not(cnn, cn);\r\n\r\n  wire Qmaster;\r\n  buffer(Qmaster);\r\n\r\n  buffer(Q);\r\n  buffer(Qn);\r\n\r\n  DLatch master(.d(d), .c(cn), .Q(Qmaster));\r\n  DLatch slave(.d(Qmaster), .c(cnn), .Q(Q), .Qn(Qn));\r\nendmodule\r\n\r\n\r\nmodule Main(\r\n  input d, c,\r\n  output Qm\r\n); \r\n\r\n  DFlipFlop dff(\r\n    .d(d),\r\n\t\t.c(c),\r\n\t\t.Q(Qm)\r\n  );\r\n\r\n  test begin\r\n    #0  { d=0, c=0 };\r\n    #1  { d=0, c=0 };\r\n    #2  { d=0, c=1 };\r\n    #3  { d=1, c=1 };\r\n    #4  { d=0, c=1 };\r\n    #5  { d=0, c=0 };\r\n    #6  { d=1, c=1 };\r\n    #7  { d=0, c=1 };\r\n    #8  { d=1, c=1 };\r\n    #9  { d=1, c=0 };\r\n    #10 { d=1, c=0 };\r\n    #11 { d=1, c=0 };\r\n    #12;\r\n  end\r\nendmodule";