export default "// SR Latch with Enable\r\n\r\nmodule SRLatchComplement (\r\n  input s, r,\r\n  output Q );\r\n\r\n  wire Qn;\r\n  assign Q = s ~& Qn;\r\n  assign Qn = Q ~& r;\r\nendmodule\r\n\r\nmodule SRLatchEnable (\r\n  input r, s, c,\r\n  output Q );\r\n\r\n  wire u1, u2, Qn;\r\n  buffer(Q);\r\n\r\n  assign u1 = s ~& c;\r\n  assign u2 = r ~& c;\r\n\r\n  SRLatchComplement latchC(.s(u1), .r(u2), .Q(Q));\r\n endmodule\r\n\r\nmodule Main(\r\n  input r, s, c,\r\n  output Q\r\n); \r\n\r\n  SRLatchEnable latchE(\r\n    .r(r),\r\n\t\t.s(s),\r\n\t\t.c(c),\r\n\t\t.Q(Q)\r\n  );\r\n\r\n  test begin\r\n    #0  {c=1, s=0, r=0};\r\n    #2  {c=1, s=1, r=0};\r\n    #4  {c=1, s=0, r=0};\r\n    #8  {c=1, s=0, r=1};\r\n    #10 {c=1, s=0, r=0};\r\n    #12 {c=0, s=1, r=0}; // no effect\r\n    #14;\r\n  end\r\nendmodule";