export default "// SR Latch with Enable with data line instead of separate set and reset lines\r\n// the clock signals the latch to follow the data line\r\n// when clock is 0 the latch holds the last Q\r\n\r\nmodule DLatch (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire dn;\r\n  not(dn, d);\r\n\r\n  wire u1, u2, Qn;\r\n  assign u1 = d ~& c;\r\n  assign u2 = dn ~& c;\r\n  assign Q = u1 ~& Qn;\r\n  assign Qn = Q ~& u2;\r\nendmodule\r\n\r\nmodule DFlipFlop (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire cn, cnn;\r\n  not(cn, c);\r\n  not(cnn, cn);\r\n\r\n  wire Qmaster;\r\n  buffer(Qmaster);\r\n\r\n  buffer(Q);\r\n  buffer(Qn);\r\n\r\n  DLatch master(.d(d), .c(cn), .Q(Qmaster));\r\n  DLatch slave(.d(Qmaster), .c(cnn), .Q(Q), .Qn(Qn));\r\nendmodule\r\n\r\nmodule Main(\r\n  input clock,\r\n  output Count0, Count1, Count2\r\n); \r\n\r\n  wire Qntf1, Qntf2, Qntf3;\r\n  buffer(Qntf1);\r\n  buffer(Qntf2);\r\n  buffer(Qntf3);\r\n\r\n  DFlipFlop tf1(\r\n    .d(Qntf1),\r\n\t\t.c(clock),\r\n\t\t.Q(Count0),\r\n    .Qn(Qntf1)\r\n  );\r\n\r\n  DFlipFlop tf2(\r\n    .d(Qntf2),\r\n\t\t.c(Qntf1),\r\n\t\t.Q(Count1),\r\n    .Qn(Qntf2)\r\n  );\r\n\r\n  DFlipFlop tf3(\r\n    .d(Qntf3),\r\n\t\t.c(Qntf2),\r\n\t\t.Q(Count2),\r\n    .Qn(Qntf3)\r\n  );\r\n\r\n  wire dec;\r\n  number(dec, Count0, Count1, Count2);\r\n\r\n  test begin\r\n    #20;\r\n  end\r\nendmodule";