export default "// Binary Up Controller from Chapter 7.5.1 of Introduction to Logic Circuits and Logic Design LaMeres\r\n\r\n// states\r\n// C0 00\r\n// C1 01\r\n// C2 10\r\n// C3 11 then back to C0\r\n\r\n//   Current State    |       Next State   |\r\n//    | Q1cur | Q0Cur |    | Q1nxt | Q0nxt |\r\n// C0 |   0   |   0   | C1 |   0   |   1   |\r\n// C1 |   0   |   1   | C2 |   1   |   0   |\r\n// C2 |   1   |   0   | C3 |   1   |   1   |\r\n// C3 |   1   |   1   | C0 |   0   |   0   |\r\n\r\n// Kmap for Q1nxt\r\n//       \\  Q1cur\r\n// Q0cur  \\   0  1\r\n//         -------\r\n//       0 |  0  1 \r\n//       1 |  1  0\r\n// Q1nxt = (~Q1cur & Q0cur) | (Q1cur & ~Q0cur)\r\n\r\n// Kmap for Q0nxt\r\n//       \\  Q1cur\r\n// Q0cur  \\   0  1\r\n//         -------\r\n//       0 |  1  1 \r\n//       1 |  0  0\r\n// Q0nxt = ~Q0cur\r\n\r\nmodule DLatch (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire dn;\r\n  not(dn, d);\r\n\r\n  wire u1, u2, Qn;\r\n  assign u1 = d ~& c;\r\n  assign u2 = dn ~& c;\r\n  assign Q = u1 ~& Qn;\r\n  assign Qn = Q ~& u2;\r\nendmodule\r\n\r\nmodule DFlipFlop (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire cn, cnn;\r\n  not(cn, c);\r\n  not(cnn, cn);\r\n\r\n  wire Qmaster;\r\n  buffer(Qmaster);\r\n\r\n  buffer(Q);\r\n  buffer(Qn);\r\n\r\n  DLatch master(.d(d), .c(cn), .Q(Qmaster));\r\n  DLatch slave(.d(Qmaster), .c(cnn), .Q(Q), .Qn(Qn));\r\nendmodule\r\n\r\nmodule NextState (\r\n  input Q1cur, Q0cur,\r\n  output Q1nxt, Q0nxt);\r\n\r\n  assign Q1nxt = (~Q1cur & Q0cur) | (Q1cur & ~Q0cur);\r\n  assign Q0nxt = ~Q0cur;\r\n\r\nendmodule\r\n\r\nmodule Main(\r\n  input clock,\r\n  output Q1cur, Q0cur\r\n); \r\n\r\n  wire Q1nxt, Q0nxt;\r\n  buffer(Q1nxt);\r\n  buffer(Q0nxt);\r\n\r\n  NextState nextState(\r\n    .Q1cur(Q1cur),\r\n    .Q0cur(Q0cur),\r\n    .Q1nxt(Q1nxt),\r\n    .Q0nxt(Q0nxt)\r\n  );\r\n\r\n  DFlipFlop Q1dff(\r\n    .d(Q1nxt),\r\n\t\t.c(clock),\r\n\t\t.Q(Q1cur)\r\n  );\r\n\r\n  DFlipFlop Q0dff(\r\n    .d(Q0nxt),\r\n\t\t.c(clock),\r\n\t\t.Q(Q0cur)\r\n  );\r\n\r\n  wire dec;\r\n  number(dec, Q0cur, Q1cur);\r\n\r\n  test begin\r\n    #20;\r\n  end\r\nendmodule";