export default "/* 1 to 2 DeMultiplexer\r\nSel selects which output to send the input to\r\nsel a | Y Z\r\n 0  0 | 0 0 \r\n 0  1 | 1 0 \r\n 1  0 | 0 0 \r\n 1  1 | 0 1 \r\n */\r\n\r\nmodule DeMux (\r\n\tinput sel,\r\n\tinput a,\r\n\toutput Y, Z);\r\n\r\n\tassign Y = ~sel & a;\r\n  assign Z = sel & a;\r\nendmodule\r\n\r\nmodule Main (\r\n  input sel, clock,\r\n  output Y, Z);\r\n\r\n  // \"clock\" is an automatic wire in main\r\n  DeMux demux(.a(clock), .sel(sel), .Y(Y), .Z(Z));\r\n\r\n  test begin\r\n    #001 {sel=0};  \r\n    #010 {sel=1}; \r\n    #020;\r\n  end\r\nendmodule";