export default "// Example of simplification\r\n// From: https://www.allaboutcircuits.com/textbook/digital/chpt-7/circuit-simplification-examples/\r\n\r\nmodule Unsimplified (\r\n  input a, b, c,\r\n  output Q );\r\n\r\n  assign Q = a & b | ((b & c) & (b | c));\r\nendmodule\r\n\r\nmodule Simplified (\r\n  input a, b, c,\r\n  output Q );\r\n\r\n  // a & b | ((b & c) & (b | c))\r\n  // &=*, |=+               AB + BC(B+C)\r\n  // Distribute             AB + BBC + BCC \r\n  // Simplify AA = A        AB + BC + BC\r\n  // Simplify A + A = A     AB + BC\r\n  // Factor                 B(A+C) \r\n\r\n  assign Q = b & (a | c);\r\nendmodule\r\n\r\nmodule Main(\r\n  input a, b, c,\r\n  output Qus, Qs\r\n); \r\n\r\n  Unsimplified unsimplified(\r\n\t\t.a(a),\r\n\t\t.b(b),\r\n\t\t.c(c),\r\n\t\t.Q(Qus)\r\n  );\r\n\r\n  Simplified simplified(\r\n\t\t.a(a),\r\n\t\t.b(b),\r\n\t\t.c(c),\r\n\t\t.Q(Qs)\r\n  );\r\n\r\n  // Check to see if Qs = Qus for all combinations of a,b,c\r\n  test begin\r\n    #0  {a=0, b=0, c=0};\r\n    #1  {a=0, b=0, c=1};\r\n    #2  {a=0, b=1, c=0};\r\n    #3  {a=0, b=1, c=1};\r\n    #4  {a=1, b=0, c=0};\r\n    #5  {a=1, b=0, c=1};\r\n    #6  {a=1, b=1, c=0};\r\n    #7  {a=1, b=1, c=1};\r\n    #8;\r\n  end\r\nendmodule";