export default "// One-hot up counter from Chapter 7.5.5 of Introduction to Logic Circuits and Logic Design LaMeres\r\n\r\nmodule DFlipFlop (\r\n  input d, c, clear, preset,\r\n  output Q, Qn);\r\n\r\n  wire notd, notc;\r\n  not(notd, d);\r\n  not(notc, c);\r\n\r\n  wire u1, u2, u3, u4, u5, u6, u7, u8;\r\n\r\n  // master\r\n  nand(u3, d, c, clear);\r\n  nand(u4, notd, c, preset);\r\n  nand(u5, u3, u6, preset);\r\n  nand(u6, u4, u5, clear);\r\n\r\n  // slave\r\n  nand(u7, u5, notc);\r\n  nand(u8, u6, notc);\r\n  nand(Q,  u7, Qn, preset);\r\n  nand(Qn, u8, Q, clear);\r\nendmodule\r\n\r\nmodule NextState (\r\n  input Q0cur, Q1cur, Q2cur,\r\n  output Q0nxt, Q1nxt, Q2nxt);\r\n\r\n  buffer(Q0nxt, Q2cur);\r\n  buffer(Q1nxt, Q0cur);\r\n  buffer(Q2nxt, Q1cur);\r\n\r\nendmodule\r\n\r\nmodule Main(\r\n  input clock, preset, reset,\r\n  output Q2cur, Q1cur, Q0cur\r\n); \r\n\r\n  wire Q0nxt, Q1nxt, Q2nxt;\r\n  buffer(Q0nxt);\r\n  buffer(Q1nxt);\r\n  buffer(Q2nxt);\r\n\r\n  NextState nextState(\r\n    .Q0cur(Q0cur),\r\n    .Q1cur(Q1cur),\r\n    .Q2cur(Q2cur),\r\n    .Q0nxt(Q0nxt),\r\n    .Q1nxt(Q1nxt),\r\n    .Q2nxt(Q2nxt)\r\n  );\r\n\r\n  DFlipFlop Q0dff(\r\n    .d(Q0nxt),\r\n\t\t.c(clock),\r\n    .preset(preset),\r\n    .clear(reset),\r\n\t\t.Q(Q0cur)\r\n  );\r\n  \r\n  DFlipFlop Q1dff(\r\n    .d(Q1nxt),\r\n\t\t.c(clock),\r\n\t\t.Q(Q1cur),\r\n    .preset(reset),\r\n    .clear(reset)\r\n  );\r\n\r\n  DFlipFlop Q2dff(\r\n    .d(Q2nxt),\r\n\t\t.c(clock),\r\n\t\t.Q(Q2cur),\r\n    .preset(reset),\r\n    .clear(reset)\r\n  );\r\n\r\n  wire bar3;\r\n  ledbar(bar3, Q0cur, Q1cur, Q2cur);\r\n\r\n  test begin\r\n    #0 {preset = 0, reset = 1};\r\n    #1 {preset = 1, reset = 1};\r\n    #20;\r\n  end\r\nendmodule";