export default "// SR Latch with Enable with data line instead of separate set and reset lines\r\n// the clock signals the latch to follow the data line\r\n// when clock is 0 the latch holds the last Q\r\n\r\nmodule DLatch (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire dn;\r\n  not(dn, d);\r\n\r\n  wire u1, u2, Qn;\r\n  assign u1 = d ~& c;\r\n  assign u2 = dn ~& c;\r\n  assign Q = u1 ~& Qn;\r\n  assign Qn = Q ~& u2;\r\nendmodule\r\n\r\nmodule DFlipFlop (\r\n  input d, c,\r\n  output Q, Qn);\r\n\r\n  wire cn, cnn;\r\n  not(cn, c);\r\n  not(cnn, cn);\r\n\r\n  wire Qmaster;\r\n  buffer(Qmaster);\r\n\r\n  buffer(Q);\r\n  buffer(Qn);\r\n\r\n  DLatch master(.d(d), .c(cn), .Q(Qmaster));\r\n  DLatch slave(.d(Qmaster), .c(cnn), .Q(Q), .Qn(Qn));\r\nendmodule\r\n\r\nmodule Main(\r\n  input clock, din,\r\n  output Out1, Out2, Out3, Out4\r\n); \r\n\r\n  DFlipFlop dff1(\r\n    .d(din),\r\n\t\t.c(clock),\r\n\t\t.Q(Out1)\r\n  );\r\n\r\n  DFlipFlop dff2(\r\n    .d(Out1),\r\n\t\t.c(clock),\r\n\t\t.Q(Out2)\r\n  );\r\n\r\n  DFlipFlop dff3(\r\n    .d(Out2),\r\n\t\t.c(clock),\r\n\t\t.Q(Out3)\r\n  );\r\n\r\n  DFlipFlop dff4(\r\n    .d(Out3),\r\n\t\t.c(clock),\r\n\t\t.Q(Out4)\r\n  );\r\n\r\n  test begin\r\n    #0 { din = 1 };\r\n    #2 { din = 0 };\r\n    #4 { din = 0 };\r\n    #6 { din = 0 };\r\n    #8;\r\n  end\r\nendmodule";